server <- function(input, output, session) {

  # ----------------------------------------------------------------------
  # Import (robust: auto-detects sheet + header row, never crashes the app)
  # ----------------------------------------------------------------------
  imported <- reactive({
    req(input$file_upload)
    path <- input$file_upload$datapath
    started <- proc.time()[["elapsed"]]

    withProgress(message = "Checking workbook", value = 0, {
      incProgress(0.20, detail = "Reading workbook and detecting the dataset sheet...")

      ans <- tryCatch({
        res <- read_dataset_sheet(path)
        incProgress(0.45, detail = "Reading the reference template...")
        Sys.sleep(0.01)
        incProgress(0.75, detail = "Preparing validation checks...")
        list(ok = TRUE, res = res, error = NULL)
      }, error = function(e) {
        list(ok = FALSE, res = NULL, error = conditionMessage(e))
      })

      ans$elapsed_seconds <- round(proc.time()[["elapsed"]] - started, 2)
      incProgress(1, detail = "Done")
      ans
    })
  })

  output$import_info <- renderText({
    imp <- imported()
    if (!imp$ok) return(paste("\u274c Import failed:", imp$error))

    d <- imp$res
    s <- count_structure(d$data)

    warn_line <- if (!d$header_detected) {
      paste0("\u26a0\ufe0f Could not confidently auto-detect the header row in sheet '", d$sheet,
             "' (used row ", d$header_row, ") - please double-check the columns below.\n")
    } else ""

    paste0(
      warn_line,
      "Done in ", format(imp$elapsed_seconds, nsmall = 2), " s",
      "   |   ", s$n_rows, " rows",
      "   |   transects: ", ifelse(is.na(s$n_transects), "n/a", s$n_transects),
      "   |   monoliths: ", ifelse(is.na(s$n_monoliths), "n/a", s$n_monoliths),
      "   |   layers: ", ifelse(is.na(s$n_layers), "n/a", s$n_layers)
    )
  })

  # Main dataset (fails gracefully with a clear message in every output if
  # import errored out, instead of crashing all tabs).
  dataset <- reactive({
    imp <- imported()
    validate(need(imp$ok, paste("Could not read the dataset sheet:", imp$error)))
    imp$res$data
  })

  # ----------------------------------------------------------------------
  # Summary dashboard
  # ----------------------------------------------------------------------

  # Descriptive metrics depend only on the imported dataset. Keeping them
  # independent from validation() and integrity() makes the Summary tab update
  # immediately after each upload, even if a later validation check fails.
  summary_dataset_metrics <- reactive({
    df <- dataset()

    n_distinct_non_missing <- function(name) {
      if (!(name %in% names(df))) return(NA_integer_)
      x <- trimws(as.character(df[[name]]))
      x <- x[!is.na(x) & x != ""]
      dplyr::n_distinct(x)
    }

    # Both current names (d_taxon, fbm_taxon, dbm_taxon) and legacy names
    # (taxon_d, taxon_fbm, taxon_dbm) are included.
    abundance_cols <- names(df)[is_taxa_column(names(df))]
    taxa <- extract_taxon_name(abundance_cols)
    taxa <- unique(tolower(trimws(taxa[!is.na(taxa) & taxa != ""])))

    soil_base_cols <- names(df)[
      grepl("^soil_", names(df), ignore.case = TRUE) &
        !grepl("_(unit|method|depth)$", names(df), ignore.case = TRUE)
    ]

    tibble::tibble(
      metric = c(
        "Rows", "Plots", "Transects", "Monoliths",
        "Layers", "Taxa", "Abundance columns", "Soil variables"
      ),
      value = c(
        nrow(df),
        n_distinct_non_missing("plot_ID"),
        n_distinct_non_missing("transect_ID"),
        n_distinct_non_missing("monolith_ID"),
        n_distinct_non_missing("layer_ID"),
        length(taxa),
        length(abundance_cols),
        length(soil_base_cols)
      )
    )
  })

  # Validation metrics are kept separate so that an error in validation does
  # not prevent the basic dataset counters from being displayed.
  summary_check_metrics <- reactive({
    v <- validation()
    integ <- integrity()

    tibble::tibble(
      metric = c(
        "Validation errors", "Validation warnings",
        "Integrity errors", "Integrity warnings"
      ),
      value = c(
        v$n_errors,
        v$n_warnings,
        integ$n_errors,
        integ$n_warnings
      )
    )
  })

  summary_metrics <- reactive({
    dplyr::bind_rows(summary_dataset_metrics(), summary_check_metrics())
  })

  format_summary_value <- function(metric_name) {
    x <- summary_dataset_metrics()
    value <- x$value[x$metric == metric_name]

    if (length(value) == 0 || is.na(value[1])) {
      "n/a"
    } else {
      format(value[1], big.mark = ",", scientific = FALSE, trim = TRUE)
    }
  }

  # Each output directly depends on summary_dataset_metrics(). Avoid creating
  # nested reactive expressions inside renderText(), which can behave
  # inconsistently in browser-based Shinylive sessions.
  output$summary_rows <- renderText({
    format_summary_value("Rows")
  })
  output$summary_plots <- renderText({
    format_summary_value("Plots")
  })
  output$summary_transects <- renderText({
    format_summary_value("Transects")
  })
  output$summary_monoliths <- renderText({
    format_summary_value("Monoliths")
  })
  output$summary_layers <- renderText({
    format_summary_value("Layers")
  })
  output$summary_taxa <- renderText({
    format_summary_value("Taxa")
  })
  output$summary_abundance <- renderText({
    format_summary_value("Abundance columns")
  })
  output$summary_soil <- renderText({
    format_summary_value("Soil variables")
  })

  output$dataset_status <- renderUI({
    v <- validation()
    integ <- integrity()
    n_errors <- v$n_errors + integ$n_errors
    n_warnings <- v$n_warnings + integ$n_warnings

    if (n_errors > 0) {
      div(
        class = "status-card status-error",
        tags$strong("Dataset requires correction. "),
        sprintf(
          "%d error(s) and %d warning(s) were detected.",
          n_errors, n_warnings
        )
      )
    } else if (n_warnings > 0) {
      div(
        class = "status-card status-warning",
        tags$strong("Dataset passed the blocking checks. "),
        sprintf(
          "No error was detected, but %d warning(s) should be reviewed.",
          n_warnings
        )
      )
    } else {
      div(
        class = "status-card status-ready",
        tags$strong("Dataset ready for submission. "),
        "No error or warning was detected by the current checks."
      )
    }
  })

  output$summary_validation_table <- renderDT({
    datatable(
      summary_check_metrics(),
      rownames = FALSE,
      options = list(dom = "t", pageLength = 10)
    )
  })

  output$download_summary <- downloadHandler(
    filename = function() {
      paste0("gsmf_dataset_summary_", Sys.Date(), ".csv")
    },
    content = function(file) {
      readr::write_csv(summary_metrics(), file)
    }
  )

  output$reference_template_info <- renderText({
    template_name <- if (!is.na(REFERENCE_TEMPLATE_PATH)) {
      basename(REFERENCE_TEMPLATE_PATH)
    } else {
      "not available"
    }

    paste0(
      "Reference template: ", template_name,
      " · Parsed fields: ", nrow(FIELD_SPEC),
      " · Checker mode: browser-only Shinylive"
    )
  })

  # ----------------------------------------------------------------------
  # Metadata sheet (best-effort extraction)
  # ----------------------------------------------------------------------
  meta <- reactive({
    req(input$file_upload)
    path <- input$file_upload$datapath
    tryCatch(
      extract_metadata_summary(path),
      error = function(e) list(sheet = NA_character_, table = tibble::tibble(), raw = tibble::tibble())
    )
  })

  # "Data access" is read from the dataset sheet's accessRights column
  # (open / restricted), not from the metadata sheet, and shown alongside
  # the other best-effort metadata fields. Built on a fixed skeleton so the
  # 5 expected rows always show up (as NA) even if the metadata sheet, the
  # accessRights column, or any other referenced column is missing from
  # this particular file - templates evolve and some columns may not be
  # filled in / may have been removed.
  meta_table <- reactive({
    wanted <- c("Dataset ID", "Data provider", "Publication reference / DOI", "Data access", "Sampling goal")

    m <- meta()$table
    imp <- imported()

    acc <- NA_character_
    if (imp$ok && "accessRights" %in% colnames(imp$res$data)) {
      vals <- unique(trimws(tolower(as.character(imp$res$data$accessRights))))
      vals <- vals[!is.na(vals) & vals != ""]
      if (length(vals) > 0) acc <- paste(vals, collapse = " | ")
    }

    values <- dplyr::bind_rows(m, tibble::tibble(field = "Data access", value = acc))
    dplyr::left_join(tibble::tibble(field = wanted), values, by = "field")
  })

  output$meta_summary_table <- renderDT({
    datatable(meta_table(), rownames = FALSE, options = list(dom = "t", pageLength = 20))
  })

  # Lightweight world map of sampling locations. Coordinates are converted
  # defensively, invalid values are discarded, and repeated rows at the same
  # sampling unit are collapsed before rendering.
  data_location_points <- reactive({
    df <- dataset()

    validate(need(all(c("latitude", "longitude") %in% names(df)),
                  "Latitude and longitude columns are required to display the map."))

    pts <- df |>
      dplyr::transmute(
        latitude = suppressWarnings(as.numeric(as.character(.data[["latitude"]]))),
        longitude = suppressWarnings(as.numeric(as.character(.data[["longitude"]]))),
        transect_ID = if ("transect_ID" %in% names(df)) as.character(.data[["transect_ID"]]) else NA_character_,
        plot_ID = if ("plot_ID" %in% names(df)) as.character(.data[["plot_ID"]]) else NA_character_,
        locality = if ("locality" %in% names(df)) as.character(.data[["locality"]]) else NA_character_
      ) |>
      dplyr::filter(
        !is.na(latitude), !is.na(longitude),
        dplyr::between(latitude, -90, 90),
        dplyr::between(longitude, -180, 180)
      ) |>
      dplyr::distinct(latitude, longitude, transect_ID, plot_ID, locality) |>
      dplyr::mutate(
        popup = paste0(
          ifelse(!is.na(transect_ID) & transect_ID != "", paste0("<b>Transect:</b> ", htmltools::htmlEscape(transect_ID), "<br>"), ""),
          ifelse(!is.na(plot_ID) & plot_ID != "", paste0("<b>Plot:</b> ", htmltools::htmlEscape(plot_ID), "<br>"), ""),
          ifelse(!is.na(locality) & locality != "", paste0("<b>Locality:</b> ", htmltools::htmlEscape(locality)), "")
        )
      )

    validate(need(nrow(pts) > 0, "No valid coordinates available for the map."))
    pts
  })

  output$data_location_map <- renderLeaflet({
    pts <- data_location_points()

    m <- leaflet::leaflet(pts, options = leaflet::leafletOptions(preferCanvas = TRUE)) |>
      leaflet::addProviderTiles(leaflet::providers$CartoDB.Positron,
                                options = leaflet::providerTileOptions(noWrap = TRUE)) |>
      leaflet::addCircleMarkers(
        lng = ~longitude, lat = ~latitude,
        radius = 4, stroke = FALSE, fillOpacity = 0.75,
        popup = ~popup
      )

    if (dplyr::n_distinct(paste(pts$latitude, pts$longitude)) == 1) {
      m |> leaflet::setView(lng = pts$longitude[1], lat = pts$latitude[1], zoom = 6)
    } else {
      m |> leaflet::fitBounds(
        lng1 = min(pts$longitude), lat1 = min(pts$latitude),
        lng2 = max(pts$longitude), lat2 = max(pts$latitude)
      )
    }
  })

  # ----------------------------------------------------------------------
  # d_ columns numeric check (kept from the original app, generalized to
  # rely on the shared check_numeric_vec() helper) + notification
  # ----------------------------------------------------------------------
  available_columns <- reactive({
    req(dataset())
    colnames(dataset())[grepl("^d_", colnames(dataset()))]
  })

  check_d_columns_are_numeric <- reactive({
    req(dataset(), available_columns())
    df <- dataset()
    d_cols <- available_columns()

    non_numeric <- d_cols[!vapply(d_cols, function(cn) all(check_numeric_vec(df[[cn]])), logical(1))]

    if (length(non_numeric) > 0) {
      showNotification(
        paste0("\u274c The following d_ columns are not numeric: ", paste(non_numeric, collapse = ", ")),
        type = "error"
      )
    } else {
      showNotification("\u2705 All d_ columns are numeric.", type = "message")
    }
    length(non_numeric) == 0
  })

  observeEvent(imported(), {
    if (imported()$ok) check_d_columns_are_numeric()
  })

  # ----------------------------------------------------------------------
  # Full validation report (mandatory fields, allowed values, ranges,
  # duplicated / unknown / empty columns, numeric abundance columns...)
  # ----------------------------------------------------------------------
  validation <- reactive({
    imp <- imported()
    validate(need(imp$ok, "Fix the import error first (see message above)."))
    validate_dataset(imp$res, FIELD_SPEC)
  })

  output$validation_counts <- renderText({
    v <- validation()
    spec_note <- if (nrow(FIELD_SPEC) == 0) paste0("\n\n", FIELD_SPEC_DIAGNOSTIC) else ""
    sprintf("Errors: %d   |   Warnings: %d   |   Info: %d%s", v$n_errors, v$n_warnings, v$n_info, spec_note)
  })

  output$validation_table <- renderDT({
    v <- validation()
    datatable(
      v$issues,
      rownames = FALSE,
      options = list(pageLength = 15, order = list(list(1, "asc")))
    ) |>
      formatStyle(
        "severity", target = "row",
        backgroundColor = styleEqual(
          c("error", "warning", "info"),
          c("#fddede", "#fff3cd", "#e7f3fe")
        )
      )
  })

  output$download_validation <- downloadHandler(
    filename = function() paste0("validation_report_", Sys.Date(), ".csv"),
    content = function(file) {
      readr::write_csv(validation()$issues, file)
    }
  )

  # ----------------------------------------------------------------------
  # Hierarchical ID integrity
  # plot_ID -> transect_ID -> monolith_ID -> layer_ID
  # ----------------------------------------------------------------------
  integrity <- reactive({
    check_id_integrity(dataset())
  })

  output$integrity_status <- renderUI({
    x <- integrity()

    if (x$n_checks_run > 0 && x$n_errors == 0 && x$n_warnings == 0) {
      div(
        class = "integrity-ok",
        span(class = "integrity-ok-icon", HTML("&#10003;")),
        span("All hierarchical ID integrity checks passed.")
      )
    }
  })

  output$integrity_counts <- renderText({
    x <- integrity()

    if (x$n_checks_run == 0) {
      return(paste(
        "No hierarchical relationship could be checked.",
        "At least two adjacent ID columns are required:",
        "plot_ID/transect_ID, transect_ID/monolith_ID, or monolith_ID/layer_ID."
      ))
    }

    if (x$n_errors == 0 && x$n_warnings == 0) {
      return(sprintf(
        "OK: %d hierarchical relationship(s) checked; no ID integrity problem found.",
        x$n_checks_run
      ))
    }

    sprintf(
      "Relationships checked: %d   |   Errors: %d   |   Warnings: %d",
      x$n_checks_run,
      x$n_errors,
      x$n_warnings
    )
  })

  output$integrity_table <- renderDT({
    x <- integrity()

    datatable(
      x$issues,
      rownames = FALSE,
      filter = "top",
      options = list(
        pageLength = 15,
        order = list(list(1, "asc")),
        scrollX = TRUE
      )
    ) |>
      formatStyle(
        "severity", target = "row",
        backgroundColor = styleEqual(
          c("error", "warning"),
          c("#fddede", "#fff3cd")
        )
      )
  })

  output$download_integrity <- downloadHandler(
    filename = function() paste0("integrity_report_", Sys.Date(), ".csv"),
    content = function(file) {
      readr::write_csv(integrity()$issues, file)
    }
  )

  # ----------------------------------------------------------------------
  # Table Visualization / Data Table tabs (kept close to the original app)
  # ----------------------------------------------------------------------
  processed_data <- reactive({
    req(dataset())
    df <- dataset()

    original_colnames <- colnames(df)
    empty_cols <- names(df)[colSums(!is.na(df)) == 0]

    if (input$remove_na_rows_vis) {
      df <- df[rowSums(!is.na(df)) > 0, , drop = FALSE]
    }
    if (input$remove_na_cols_vis) {
      df <- df[, colSums(!is.na(df)) > 0, drop = FALSE]
    }

    removed_cols <- setdiff(original_colnames, colnames(df))

    output$removed_cols_text <- renderText({
      if (length(removed_cols) > 0) paste("Removed Columns:", paste(removed_cols, collapse = ", ")) else "No columns removed."
    })
    output$empty_cols_text <- renderText({
      if (length(empty_cols) > 0) paste("Empty Columns:", paste(empty_cols, collapse = ", ")) else "No empty columns."
    })

    df
  })

  output$data_plot <- renderPlot({
    req(processed_data())
    vis_dat(processed_data(), sort_type = FALSE) +
      ggplot2::theme(
        # Rotating axis text 90deg without vjust/hjust set makes ggplot
        # reserve an oversized (near-original-width) label area, which is
        # what created the big blank gap above the raster. Pinning
        # vjust/hjust fixes the label bounding box to its actual rotated
        # size.
        axis.text.x = ggplot2::element_text(angle = 90, hjust = 1, vjust = 0.5, size = 7),
        plot.margin = ggplot2::margin(t = 5, r = 5, b = 5, l = 5)
      )
  })
}

ui <- fluidPage(
  tags$head(
    tags$title("GlobalSoilMacroFauna Dataset Checker"),
    tags$style(HTML("
      body { background-color: #fafafa; }
      .container-fluid { max-width: 1450px; }
      .gsmf-header {
        display: flex; align-items: center; gap: 24px;
        padding: 18px 22px; margin: 14px 0 18px 0;
        background: white; border: 1px solid #e6e6e6;
        border-radius: 10px;
      }
      .gsmf-logo { width: 150px; max-height: 120px; object-fit: contain; }
      .gsmf-title { margin: 0 0 5px 0; font-size: 30px; font-weight: 600; }
      .gsmf-subtitle { margin: 0; color: #555; font-size: 16px; }
      .privacy-note {
        padding: 10px 14px; margin: 12px 0 16px 0;
        border-left: 4px solid #a74f0d; background: #fff7f0;
      }
      .upload-panel {
        padding: 18px; margin-bottom: 16px; background: white;
        border: 1px solid #e6e6e6; border-radius: 10px;
      }
      .metric-card {
        min-height: 105px; padding: 14px 16px; margin-bottom: 15px;
        background: white; border: 1px solid #e6e6e6;
        border-radius: 8px;
      }
      .metric-label { color: #666; font-size: 13px; text-transform: uppercase; letter-spacing: .04em; }
      .metric-value { margin-top: 4px; font-size: 27px; font-weight: 600; }
      .status-card { padding: 16px; border-radius: 8px; margin-bottom: 18px; font-size: 17px; }
      .status-ready { background: #e9f7ef; border: 1px solid #b8dfc7; }
      .status-warning { background: #fff5d9; border: 1px solid #ead28a; }
      .status-error { background: #fdeaea; border: 1px solid #e6b8b8; }
      .integrity-ok {
        display: inline-flex; align-items: center; gap: 9px;
        padding: 10px 14px; margin: 4px 0 12px 0;
        background: #e9f7ef; border: 1px solid #b8dfc7;
        border-radius: 8px; font-size: 16px;
      }
      .integrity-ok-icon {
        display: inline-flex; align-items: center; justify-content: center;
        width: 25px; height: 25px; border-radius: 50%;
        background: #2e8b57; color: white; font-weight: 700;
      }
      .tab-content { padding-top: 12px; }
      @media (max-width: 700px) {
        .gsmf-header { flex-direction: column; text-align: center; }
        .gsmf-logo { width: 120px; }
      }
    "))
  ),

  div(
    class = "gsmf-header",
    tags$img(src = "gsmf_logo.png", class = "gsmf-logo", alt = "GlobalSoilMacroFauna logo"),
    div(
      h1("GlobalSoilMacroFauna Dataset Checker", class = "gsmf-title"),
      p("Official validation tool for datasets submitted to the GlobalSoilMacroFauna database.",
        class = "gsmf-subtitle"),
      tags$a(
        href = "https://www.globalsoilmacrofauna.com/",
        target = "_top",
        rel = "noopener noreferrer",
        "← Return to GlobalSoilMacroFauna"
      )
    )
  ),

  div(
    class = "privacy-note",
    tags$strong("Private by design. "),
    "Your dataset will not be sent to our server."
  ),

  div(
    class = "upload-panel",
    fluidRow(
      column(
        width = 7,
        fileInput(
          "file_upload", "Upload your Excel workbook",
          multiple = FALSE,
          accept = c(".xlsx"),
          buttonLabel = "Browse...",
          placeholder = "Drag and drop your file here"
        )
      ),
      column(
        width = 5,
        h4("GSMF data template"),
        tags$a(
          href = "https://doi.org/10.5281/zenodo.4543852",
          target = "_blank",
          rel = "noopener noreferrer",
          "Permanent template DOI: 10.5281/zenodo.4543852"
        )
      )
    ),
    verbatimTextOutput("import_info")
  ),

  tabsetPanel(
    id = "main_tabs",

    tabPanel(
      "Summary",
      br(),
      uiOutput("dataset_status"),
      fluidRow(
        column(3, div(class = "metric-card", div(class = "metric-label", "Rows"), div(class = "metric-value", textOutput("summary_rows", inline = TRUE)))),
        column(3, div(class = "metric-card", div(class = "metric-label", "Plots"), div(class = "metric-value", textOutput("summary_plots", inline = TRUE)))),
        column(3, div(class = "metric-card", div(class = "metric-label", "Transects"), div(class = "metric-value", textOutput("summary_transects", inline = TRUE)))),
        column(3, div(class = "metric-card", div(class = "metric-label", "Monoliths"), div(class = "metric-value", textOutput("summary_monoliths", inline = TRUE))))
      ),
      fluidRow(
        column(3, div(class = "metric-card", div(class = "metric-label", "Layers"), div(class = "metric-value", textOutput("summary_layers", inline = TRUE)))),
        column(3, div(class = "metric-card", div(class = "metric-label", "Taxa"), div(class = "metric-value", textOutput("summary_taxa", inline = TRUE)))),
        column(3, div(class = "metric-card", div(class = "metric-label", "Abundance columns"), div(class = "metric-value", textOutput("summary_abundance", inline = TRUE)))),
        column(3, div(class = "metric-card", div(class = "metric-label", "Soil variables"), div(class = "metric-value", textOutput("summary_soil", inline = TRUE))))
      ),
      h4("Dataset validation"),
      DTOutput("summary_validation_table"),
      br(),
      downloadButton("download_summary", "Download dataset summary (CSV)"),
      br(), br(),
      tags$small(textOutput("reference_template_info", inline = TRUE))
    ),

    tabPanel(
      "Metadata",
      br(),
      p("Complete or verify these fields in the workbook when necessary."),
      DTOutput("meta_summary_table")
    ),

    tabPanel(
      "Data location",
      br(),
      p("Check the geographic distribution of the sampling locations and identify possible coordinate errors."),
      leafletOutput("data_location_map", height = "430px")
    ),

    tabPanel(
      "Validation report",
      br(),
      verbatimTextOutput("validation_counts"),
      downloadButton("download_validation", "Download validation report (CSV)"),
      br(), br(),
      DTOutput("validation_table")
    ),

    tabPanel(
      "Integrity checks",
      br(),
      h4("Hierarchical ID integrity"),
      p("Checks that each transect_ID belongs to only one plot_ID, each monolith_ID to only one transect_ID, and each layer_ID to only one monolith_ID."),
      uiOutput("integrity_status"),
      verbatimTextOutput("integrity_counts"),
      downloadButton("download_integrity", "Download integrity report (CSV)"),
      br(), br(),
      DTOutput("integrity_table")
    ),

    tabPanel(
      "Table visualization",
      br(),
      checkboxInput("remove_na_rows_vis", "Remove rows containing only NA", value = FALSE),
      checkboxInput("remove_na_cols_vis", "Remove columns containing only NA", value = FALSE),
      verbatimTextOutput("removed_cols_text"),
      verbatimTextOutput("empty_cols_text"),
      plotOutput("data_plot", height = "650px")
    )
  )
)

# ==============================================================================
# add_loading_overlay.R
#
# Patches a Shinylive-exported index.html to add a friendly loading screen
# ("This can take up to 30 seconds on first visit...") that disappears
# automatically once the Shiny app starts rendering.
#
# Run this AFTER shinylive::export(), pointing at the exported site directory
# (the one containing index.html + the shinylive/ subfolder).
#
# Usage:
#   source("add_loading_overlay.R")
#   add_loading_overlay("C:/github_repos/globalsoilmacrofauna/globalsoilmacrofauna.github.io/dataset-checker")
#
# Safe to run multiple times: if the overlay is already present, it is
# replaced rather than duplicated.
# ==============================================================================

add_loading_overlay <- function(site_dir,
                                 message_html = "Loading the data-checking tool&hellip;<br>This can take up to 30 seconds on your first visit. Thanks for your patience!") {

  index_path <- file.path(site_dir, "index.html")
  if (!file.exists(index_path)) {
    stop("No index.html found at: ", index_path)
  }

  html <- readLines(index_path, warn = FALSE, encoding = "UTF-8")
  html <- paste(html, collapse = "\n")

  start_marker <- "<!-- GSMF_LOADING_OVERLAY_START -->"
  end_marker   <- "<!-- GSMF_LOADING_OVERLAY_END -->"

  # If a previous overlay is already present (re-running the script after a
  # fresh export), strip it out first so we don't duplicate it.
  if (grepl(start_marker, html, fixed = TRUE)) {
    html <- gsub(
      paste0(start_marker, "(?s).*?", end_marker),
      "",
      html,
      perl = TRUE
    )
  }

  overlay_css <- '
    <style>
      #gsmf-loading-overlay {
        position: fixed;
        inset: 0;
        z-index: 9999;
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        background: #ffffff;
        font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "Open Sans", sans-serif;
        text-align: center;
        padding: 24px;
      }
      #gsmf-loading-overlay .gsmf-spinner {
        width: 42px;
        height: 42px;
        border: 4px solid #e0e0e0;
        border-top-color: #5c7a4f;
        border-radius: 50%;
        animation: gsmf-spin 0.9s linear infinite;
        margin-bottom: 18px;
      }
      #gsmf-loading-overlay p {
        color: #444;
        font-size: 0.95rem;
        max-width: 380px;
        margin: 0;
      }
      @keyframes gsmf-spin {
        to { transform: rotate(360deg); }
      }
      #gsmf-loading-overlay.gsmf-hidden {
        opacity: 0;
        pointer-events: none;
        transition: opacity 0.4s ease;
      }
    </style>'

  overlay_body <- sprintf('
    <div id="gsmf-loading-overlay">
      <div class="gsmf-spinner"></div>
      <p>%s</p>
    </div>

    <script>
      (function () {
        var overlay = document.getElementById("gsmf-loading-overlay");
        var root = document.getElementById("root");

        function hideOverlay() {
          if (overlay) {
            overlay.classList.add("gsmf-hidden");
            setTimeout(function () {
              if (overlay && overlay.parentNode) {
                overlay.parentNode.removeChild(overlay);
              }
            }, 500);
          }
        }

        var observer = new MutationObserver(function () {
          if (root && root.childNodes.length > 0) {
            hideOverlay();
            observer.disconnect();
          }
        });
        if (root) {
          observer.observe(root, { childList: true, subtree: true });
        }

        // Safety net in case detection fails for any reason
        setTimeout(hideOverlay, 60000);
      })();
    </script>', message_html)

  overlay_style_block <- paste0(
    start_marker, "\n",
    overlay_css, "\n",
    end_marker
  )

  overlay_body_block <- paste0(
    start_marker, "\n",
    overlay_body, "\n",
    end_marker
  )

  if (!grepl("</head>", html, fixed = TRUE)) {
    stop("Could not find </head> in ", index_path, " - file structure may have changed.")
  }
  if (!grepl("<body>", html, fixed = TRUE)) {
    stop("Could not find <body> in ", index_path, " - file structure may have changed.")
  }

  html <- sub("</head>", paste0(overlay_style_block, "\n</head>"), html, fixed = TRUE)
  html <- sub("<body>", paste0("<body>\n", overlay_body_block), html, fixed = TRUE)

  writeLines(html, index_path, useBytes = TRUE)
  cat("Loading overlay added to:", index_path, "\n")
  invisible(TRUE)
}
